import{_ as a,o as e,c as l,a2 as i}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 攻城戰完全手冊：破城而入的藝術","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/siege-warfare.md","filePath":"bannerlord/siege-warfare.md"}'),r={name:"bannerlord/siege-warfare.md"};function d(h,t,o,n,s,c){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="騎砍2-攻城戰完全手冊-破城而入的藝術" tabindex="-1">騎砍2 | 攻城戰完全手冊：破城而入的藝術 <a class="header-anchor" href="#騎砍2-攻城戰完全手冊-破城而入的藝術" aria-label="Permalink to &quot;騎砍2 | 攻城戰完全手冊：破城而入的藝術&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>攻城是騎砍2最難的戰鬥類型。你面對的是城牆、守軍、投石車和時間壓力。這篇從準備到破城，完整拆解。</p><hr><h2 id="一、攻城前準備" tabindex="-1">一、攻城前準備 <a class="header-anchor" href="#一、攻城前準備" aria-label="Permalink to &quot;一、攻城前準備&quot;">​</a></h2><h3 id="_1-1-你需要什麼" tabindex="-1">1.1 你需要什麼 <a class="header-anchor" href="#_1-1-你需要什麼" aria-label="Permalink to &quot;1.1 你需要什麼&quot;">​</a></h3><table tabindex="0"><thead><tr><th>條件</th><th style="text-align:center;">最低標準</th><th style="text-align:center;">建議標準</th></tr></thead><tbody><tr><td>兵力</td><td style="text-align:center;">100+</td><td style="text-align:center;">150+</td></tr><tr><td>攻城器械</td><td style="text-align:center;">攻城錘 + 攻城塔</td><td style="text-align:center;">加上投石機</td></tr><tr><td>食物</td><td style="text-align:center;">夠全軍 7 天</td><td style="text-align:center;">夠全軍 14 天</td></tr><tr><td>時間</td><td style="text-align:center;">圍城 3-7 天</td><td style="text-align:center;">看你是否急</td></tr></tbody></table><h3 id="_1-2-選對目標" tabindex="-1">1.2 選對目標 <a class="header-anchor" href="#_1-2-選對目標" aria-label="Permalink to &quot;1.2 選對目標&quot;">​</a></h3><ul><li>優先挑<strong>邊境城堡</strong>而非核心大城</li><li>駐軍少於 200 人的優先</li><li>糧食儲備低的 → 圍城時間短</li><li>附近沒有敵方大軍的</li></ul><hr><h2 id="二、圍城階段" tabindex="-1">二、圍城階段 <a class="header-anchor" href="#二、圍城階段" aria-label="Permalink to &quot;二、圍城階段&quot;">​</a></h2><h3 id="_2-1-圍城營地" tabindex="-1">2.1 圍城營地 <a class="header-anchor" href="#_2-1-圍城營地" aria-label="Permalink to &quot;2.1 圍城營地&quot;">​</a></h3><p>點右鍵攻擊城鎮 → 選擇「圍城」→ 進入圍城介面。</p><p>圍城期間：</p><ul><li>敵方糧食每天消耗</li><li>守軍數量會因飢餓而減少</li><li>你可以建造攻城器械</li></ul><h3 id="_2-2-建造器械" tabindex="-1">2.2 建造器械 <a class="header-anchor" href="#_2-2-建造器械" aria-label="Permalink to &quot;2.2 建造器械&quot;">​</a></h3><table tabindex="0"><thead><tr><th>器械</th><th>用途</th><th style="text-align:center;">建造時間</th></tr></thead><tbody><tr><td>攻城錘</td><td>撞開城門</td><td style="text-align:center;">2-3 天</td></tr><tr><td>攻城塔</td><td>靠上城牆讓步兵登城</td><td style="text-align:center;">3-4 天</td></tr><tr><td>投石機</td><td>轟炸城牆/守軍/敵方器械</td><td style="text-align:center;">3-5 天</td></tr><tr><td>弩砲</td><td>打守軍</td><td style="text-align:center;">2-3 天</td></tr></tbody></table><blockquote><p>💡 優先建投石機 → 轟垮敵方投石車 → 再建攻城塔和攻城錘。</p></blockquote><h3 id="_2-3-小心援軍" tabindex="-1">2.3 小心援軍 <a class="header-anchor" href="#_2-3-小心援軍" aria-label="Permalink to &quot;2.3 小心援軍&quot;">​</a></h3><p>圍城時隨時注意地圖。如果敵方大軍靠近：</p><ul><li>兵力相當 → 可以打</li><li>敵方比你多 → 立刻撤退，不要硬扛</li></ul><hr><h2 id="三、攻城戰階段" tabindex="-1">三、攻城戰階段 <a class="header-anchor" href="#三、攻城戰階段" aria-label="Permalink to &quot;三、攻城戰階段&quot;">​</a></h2><h3 id="_3-1-開場" tabindex="-1">3.1 開場 <a class="header-anchor" href="#_3-1-開場" aria-label="Permalink to &quot;3.1 開場&quot;">​</a></h3><ol><li>讓投石機先轟（如果有的話）</li><li>步兵推攻城塔 + 攻城錘前進</li><li>弓兵在城下壓制城牆上的敵方弓兵</li><li>騎兵在後方待命（騎兵攻城沒用）</li></ol><h3 id="_3-2-城牆戰鬥" tabindex="-1">3.2 城牆戰鬥 <a class="header-anchor" href="#_3-2-城牆戰鬥" aria-label="Permalink to &quot;3.2 城牆戰鬥&quot;">​</a></h3><p>攻城塔靠上城牆後 → 步兵登城。</p><ul><li><strong>不要第一個衝上去！</strong> 讓小兵先上</li><li>舉盾推進，城牆上很擠</li><li>優先打敵方弓兵（他們在射你的後續部隊）</li><li>清完一段城牆再往前推</li></ul><h3 id="_3-3-城門突破" tabindex="-1">3.3 城門突破 <a class="header-anchor" href="#_3-3-城門突破" aria-label="Permalink to &quot;3.3 城門突破&quot;">​</a></h3><p>攻城錘撞開城門後：</p><ul><li>立刻派重步兵進入</li><li>城門內通常有守軍堵門</li><li>斯特吉亞斧兵在巷戰中無敵</li><li>清完城門區 → 往城中心推進</li></ul><h3 id="_3-4-城鎮中心" tabindex="-1">3.4 城鎮中心 <a class="header-anchor" href="#_3-4-城鎮中心" aria-label="Permalink to &quot;3.4 城鎮中心&quot;">​</a></h3><p>最後一波敵軍會集中在城鎮中心。</p><ul><li>讓你的部隊集合後再衝</li><li>不要自己一個人衝進去</li><li>打完中心 → 攻城結束</li></ul><hr><h2 id="四、防守方戰術" tabindex="-1">四、防守方戰術 <a class="header-anchor" href="#四、防守方戰術" aria-label="Permalink to &quot;四、防守方戰術&quot;">​</a></h2><h3 id="_4-1-器械優先" tabindex="-1">4.1 器械優先 <a class="header-anchor" href="#_4-1-器械優先" aria-label="Permalink to &quot;4.1 器械優先&quot;">​</a></h3><p>投石車優先打：</p><ol><li>敵方攻城塔（最優先！塔靠牆就完了）</li><li>敵方攻城錘</li><li>敵方投石機</li></ol><h3 id="_4-2-城牆部署" tabindex="-1">4.2 城牆部署 <a class="header-anchor" href="#_4-2-城牆部署" aria-label="Permalink to &quot;4.2 城牆部署&quot;">​</a></h3><ul><li>弓兵放城牆射推塔的敵兵</li><li>步兵預備在城門後</li><li>你自己站城牆高處往下丟石頭</li></ul><h3 id="_4-3-突圍" tabindex="-1">4.3 突圍 <a class="header-anchor" href="#_4-3-突圍" aria-label="Permalink to &quot;4.3 突圍&quot;">​</a></h3><p>如果你兵力夠多，可以在敵方圍城時主動出城迎戰——這樣就不用打城牆戰了。</p><hr><h2 id="五、攻城案例-新手第一座城" tabindex="-1">五、攻城案例：新手第一座城 <a class="header-anchor" href="#五、攻城案例-新手第一座城" aria-label="Permalink to &quot;五、攻城案例：新手第一座城&quot;">​</a></h2><p>推薦第一座攻城目標：<strong>瓦蘭迪亞或斯特吉亞邊境的低守軍城堡</strong>（遠離帝國核心區）。</p><p>步驟：</p><ol><li>準備 120+ 精兵 + 食物 14 天</li><li>確認附近沒有敵方軍團</li><li>圍城 → 建攻城塔 + 攻城錘</li><li>等 3-5 天糧食耗盡</li><li>發起總攻 → 拿下！</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./combat-tactics.html">騎砍2 | 戰鬥技巧完全指南</a></li><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',57)])])}const _=a(r,[["render",d]]);export{b as __pageData,_ as default};
